import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';
import Dashboard from './Dashboard';

function App() {
    const [user, setUser] = useState(null);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [view, setView] = useState('login'); 
    
    const [analysisData, setAnalysisData] = useState(null);
    const [productName, setProductName] = useState('');
    const [barcode, setBarcode] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    // Manual Entry States
    const [manualName, setManualName] = useState('');
    const [manualSugar, setManualSugar] = useState('');
    const [manualProtein, setManualProtein] = useState('');

    useEffect(() => {
        // Get initial session
        supabase.auth.getSession().then(({ data: { session } }) => {
            setUser(session?.user ?? null);
        });

        // Listen for auth changes (Login/Logout)
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setUser(session?.user ?? null);
            if (session?.user) setView('choice');
        });

        return () => subscription.unsubscribe();
    }, []);

    const handleAuth = async (type) => {
        setIsLoading(true);
        const { error } = type === 'login' 
            ? await supabase.auth.signInWithPassword({ email, password })
            : await supabase.auth.signUp({ email, password });
        
        if (error) alert(error.message);
        setIsLoading(false);
    };

    const handleBarcodeSearch = async () => {
        if (!barcode) return;
        setIsLoading(true);
        try {
            const response = await fetch(`http://localhost:8000/scan-barcode/${barcode}`);
            const result = await response.json();
            if (result.status === "success") {
                setAnalysisData(result.data);
                setProductName(result.product_name);
            } else { alert(result.message); }
        } catch (err) { alert("Search failed"); }
        finally { setIsLoading(false); }
    };

    const saveToDietPlan = async (customData = null) => {
        if (!user) return;
        
        const entry = customData || {
            product_name: productName,
            analysis_json: analysisData,
            user_id: user.id
        };

        const { error } = await supabase.from('diet_logs').insert([entry]);

        if (error) {
            alert("Error saving to plan: " + error.message);
        } else {
            alert("Successfully added to your Diet Plan!");
            setAnalysisData(null);
            setView('choice');
        }
    };

    const handleManualAdd = () => {
        if (!manualName) return;
        const customEntry = {
            product_name: manualName,
            analysis_json: [
                { rsid: `Sugar: ${manualSugar}g`, trait: "User Log", genotype: "Manual", recommendation: "Manually entered nutritional data." },
                { rsid: `Protein: ${manualProtein}g`, trait: "User Log", genotype: "Manual", recommendation: "Manually entered nutritional data." }
            ],
            user_id: user.id
        };
        saveToDietPlan(customEntry);
    };

    if (!user) {
        return (
            <div style={styles.container}>
                <h1 style={styles.title}>NutriGen<span style={{color: '#38a169'}}>.</span></h1>
                <div style={styles.card}>
                    <h3 style={{textAlign: 'center'}}>{view === 'login' ? 'Login' : 'Join NutriGen'}</h3>
                    <input style={styles.input} placeholder="Email" onChange={e => setEmail(e.target.value)} />
                    <input style={styles.input} type="password" placeholder="Password" onChange={e => setPassword(e.target.value)} />
                    <button style={styles.btn} onClick={() => handleAuth(view)} disabled={isLoading}>
                        {isLoading ? 'Processing...' : (view === 'login' ? 'Login' : 'Sign Up')}
                    </button>
                    <p onClick={() => setView(view === 'login' ? 'signup' : 'login')} style={styles.backLink}>
                        {view === 'login' ? 'Need an account? Sign up' : 'Already have an account? Login'}
                    </p>
                </div>
            </div>
        );
    }

    return (
        <div style={styles.container}>
            <header style={styles.header}>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                    <h1 style={styles.title}>NutriGen.</h1>
                    <button onClick={() => supabase.auth.signOut()} style={styles.logoutBtn}>Logout</button>
                </div>
            </header>

            <main>
                {analysisData ? (
                    <div>
                        <h2 style={styles.productHeading}>{productName}</h2>
                        <div style={{display: 'flex', gap: '10px', marginBottom: '20px'}}>
                            <button style={styles.btn} onClick={() => saveToDietPlan()}>Add to Diet Plan</button>
                            <button style={{...styles.btn, background: '#444'}} onClick={() => setAnalysisData(null)}>Cancel</button>
                        </div>
                        <Dashboard data={analysisData} onReset={() => setAnalysisData(null)} />
                    </div>
                ) : view === 'choice' ? (
                    <div style={styles.choiceGrid}>
                        <div style={styles.optionCard} onClick={() => setView('scan')}>🔍 Barcode Search</div>
                        <div style={styles.optionCard} onClick={() => setView('manual_entry')}>📝 Manual Food Entry</div>
                    </div>
                ) : view === 'manual_entry' ? (
                    <div style={styles.card}>
                        <h3>Manual Log</h3>
                        <input style={styles.input} placeholder="Food Item Name" value={manualName} onChange={e => setManualName(e.target.value)} />
                        <input style={styles.input} placeholder="Sugars (g)" type="number" value={manualSugar} onChange={e => setManualSugar(e.target.value)} />
                        <input style={styles.input} placeholder="Protein (g)" type="number" value={manualProtein} onChange={e => setManualProtein(e.target.value)} />
                        <button style={styles.btn} onClick={handleManualAdd}>Save to Plan</button>
                        <button onClick={() => setView('choice')} style={styles.backLink}>Go Back</button>
                    </div>
                ) : (
                    <div style={styles.card}>
                        <h3>Barcode Scanner</h3>
                        <input style={styles.input} placeholder="Enter Barcode" value={barcode} onChange={e => setBarcode(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleBarcodeSearch()} />
                        <button style={styles.btn} onClick={handleBarcodeSearch} disabled={isLoading}>
                            {isLoading ? 'Scanning...' : 'Analyze'}
                        </button>
                        <button onClick={() => setView('choice')} style={styles.backLink}>Back to Menu</button>
                    </div>
                )}
            </main>
        </div>
    );
}

const styles = {
    container: { maxWidth: '800px', margin: '0 auto', padding: '40px 20px', color: '#fff', fontFamily: 'sans-serif' },
    header: { marginBottom: '30px' },
    title: { fontSize: '2.5rem', fontWeight: '800', margin: 0 },
    card: { background: '#1a1a1a', padding: '30px', borderRadius: '20px', border: '1px solid #333' },
    input: { width: '100%', padding: '12px', margin: '10px 0', borderRadius: '10px', background: '#2d2d2d', border: '1px solid #444', color: '#fff', boxSizing: 'border-box' },
    btn: { background: '#38a169', color: '#fff', padding: '12px', width: '100%', borderRadius: '10px', border: 'none', fontWeight: 'bold', cursor: 'pointer', flex: 1 },
    optionCard: { padding: '50px 20px', background: '#1a1a1a', border: '1px solid #333', borderRadius: '20px', cursor: 'pointer', textAlign: 'center', fontSize: '1.2rem', transition: '0.2s' },
    choiceGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' },
    logoutBtn: { background: 'none', border: '1px solid #ff4d4d', color: '#ff4d4d', padding: '5px 15px', borderRadius: '8px', cursor: 'pointer' },
    backLink: { color: '#aaa', cursor: 'pointer', textAlign: 'center', marginTop: '15px', display: 'block', fontSize: '0.9rem' },
    productHeading: { color: '#38a169', textAlign: 'center', textTransform: 'capitalize' }
};

export default App;
